mapper.update:
		/* PointRecovery_SQL.updateCustPointGiveBaseBas */
		UPDATE NMCP_CUST_POINT_GIVE_BASE_BAS@DL_MCP
		SET  TOT_ACU_POINT = TOT_ACU_POINT + #{point}
            ,TOT_REMAIN_POINT = TOT_REMAIN_POINT + #{point}
			,POINT_SUM_BASE_DATE = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
			,AMD_IP = #{cretIp}
			,AMD_DT = SYSDATE
			,AMD_ID = #{cretId}
		WHERE SVC_CNTR_NO = #{svcCntrNo}

mapper.insert:
/* PointRecovery_SQL.insertCustPointTxn */

    select SQ_POINT_TXN_SEQ.NEXTVAL@DL_MCP FROM DUAL

INSERT INTO NMCP_CUST_POINT_TXN@DL_MCP
(
	POINT_TXN_SEQ
	,POINT_CUST_SEQ
	,POINT_DIV_CD
	,POINT_TRT_CD
	,POINT_GIVE_BASE_SEQ
	,POINT
	,TOT_REMAIN_POINT
	,POINT_USE_POSBL_ST_DATE
	,POINT_USE_POSBL_END_DATE
	,POINT_TXN_RSN_CD
	,POINT_TXN_DTL_RSN_DESC
	,POINT_ALL_GIVE_SEQ
	,USER_POINT_TRT_SEQ
	,REQUEST_KEY
	,POINT_TRT_DT
	,POINT_TRT_MEMO
	,CRET_IP
	,CRET_DT
	,CRET_ID
	,AMD_IP
	,AMD_DT
	,AMD_ID
)
VALUES
(
	#{pointTxnSeq}
	,#{pointCustSeq}
	,#{pointDivCd}
	,'S'
	,#{pointGiveBaseSeq}
	,#{point}
	, (SELECT TOT_REMAIN_POINT FROM NMCP_CUST_POINT_GIVE_BASE_BAS@DL_MCP WHERE SVC_CNTR_NO = #{svcCntrNo})
	,to_char(SYSDATE,'yyyymmddhh24miss')
	,to_char(add_months(SYSDATE,12),'yyyymmddhh24miss')
	,#{pointTxnRsnCd}
	,#{pointTxnDtlRsnDesc} ||' 구매취소에 따른 포인트 재적립'
	,#{pointAllGiveSeq}
	,#{userPointTrtSeq}
	,#{requestKey}
	,SYSDATE
	,#{pointTrtMemo}
	,#{cretIp}
	,SYSDATE
	,#{cretId}
	,#{cretIp}
	,SYSDATE
	,#{cretId}
)

/* PointRecovery_SQL.insertCustPointAcuTxnDtl */

	SELECT SQ_POINT_TXN_SEQ.CURRVAL@DL_MCP FROM DUAL

INSERT INTO NMCP_CUST_POINT_ACU_TXN_DTL@DL_MCP
(
	POINT_TXN_SEQ
	,REMAIN_POINT
	,CRET_IP
	,CRET_DT
	,CRET_ID
	,AMD_IP
	,AMD_DT
	,AMD_ID
)
VALUES
(
	#{pointTxnSeq}
	,#{point}
	,#{cretIp}
	,SYSDATE
	,#{cretId}
	,#{cretIp}
	,SYSDATE
	,#{cretId}
)

mapper.select:
/* PointRecovery_SQL.selectUsePointAmt */
SELECT NVL(POINT,0) AS POINT
FROM NMCP_CUST_POINT_TXN@DL_MCP
WHERE POINT_TRT_CD  = 'U'
  AND REQUEST_KEY = #{requestKey}
  AND ROWNUM = 1
